import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: empty
  it.todo("empty item list quote → premium 5 G (processing fee only)");

  // Base premiums per item type
  it.todo("quote for single sword → 105 G (100 base + 5 fee)");
  it.todo("quote for single amulet → 65 G (60 base + 5 fee)");
  it.todo("quote for single staff → 85 G (80 base + 5 fee)");
  it.todo("quote for single potion → 45 G (40 base + 5 fee)");

  // Component rules
  it.todo("quote for 1 rune → 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes → 55 G (50 base + 5 fee)");
  it.todo("quote for 3 runes → 65 G (60 block + 5 fee)");
  it.todo("quote for 4 runes → 105 G (100 base, no block + 5 fee)");
  it.todo("quote for 7 runes → 180 G (175 base + 5 fee)");

  // Alike clarification
  it.todo("quote for 2 runes + 1 moonstone → 80 G (75 base, no block + 5 fee)");
  it.todo("quote for 3 runes + 3 moonstones → 125 G (120 base, two blocks + 5 fee)");

  // Cursed surcharge
  it.todo("cursed sword (steel, ench 3), newcomer → 165 G (100 + 50 curse + 10 first + 5 fee)");

  // High enchantment surcharge
  it.todo("sword enchantment 5 (not cursed), newcomer → 145 G (100 + 30 high-ench + 10 first + 5 fee)");
  it.todo("sword enchantment 4 (not cursed), newcomer → 115 G (100 + 10 first + 5 fee, no high-ench)");
  it.todo("cursed sword enchantment 5, newcomer → 195 G (100 + 50 curse + 30 high-ench + 10 first + 5 fee)");

  // Loyalty
  it.todo("loyalty discount applies at exactly 2 years (sword, no other modifiers, newcomer-first contract) → 95 G (100 - 20 loyalty + 10 first + 5 fee)");

  // First insurance & follow-up
  it.todo("second contract for long-standing customer (3 yrs) with cursed sword ench 7 → 160 G");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet, newcomer → policy base 160 + curse 50 + first 16 + fee 5 = 231 G");

  // Rounding (premium up)
  it.todo("premium calculation 197.5 G → 198 G (rounded up)");

  // CLAIM examples
  // Standard reimbursement
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("rune (insurance 250), damage 200 G → payout 100 G");

  // Enchantment threshold vs dragon material
  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G (high-ench wins)");
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (high-ench applies)");

  // Multiple damages
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // Multiple items same type
  it.todo("two swords insured → insurance sum 2000, cap 4000");
  it.todo("two sword damages with two swords insured → both processed with own deductible");
  it.todo("two sword damages with only one sword insured → error (non-zero exit)");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium with modifiers 165 G but cap still 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
  it.todo("sword (cap 2000): claim 1500 → payout 1400, remaining 600; next claim 1500 → payout 600, remaining 0");

  // Rounding (payout down)
  it.todo("payout calculation 350.5 G → 350 G (rounded down)");

  // Error cases
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references item not in policy → CLI exits non-zero, error on stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero, error on stderr");
});

