import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: empty
  it("empty item list quote → premium 5 G (processing fee only)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums per item type
  it("quote for single sword for newcomer → 115 G (100 base + 10 first + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote for single amulet → 65 G (60 base + 5 fee)");
  it.todo("quote for single staff → 85 G (80 base + 5 fee)");
  it.todo("quote for single potion → 45 G (40 base + 5 fee)");

  // Component rules
  it.todo("quote for 1 rune → 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes → 55 G (50 base + 5 fee)");
