  it.todo("rune (insurance 250), damage 200 G → payout 100 G");

  // Enchantment threshold vs dragon material
  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G (high-ench wins)");
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (high-ench applies)");

  // Multiple damages
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // Multiple items same type
  it.todo("two swords insured → insurance sum 2000, cap 4000");
  it.todo("two sword damages with two swords insured → both processed with own deductible");
  it.todo("two sword damages with only one sword insured → error (non-zero exit)");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium with modifiers 165 G but cap still 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
