type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemBase = (item: Item): number => BASE_PREMIUM[item.type];

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + itemBase(item), 0);
    const firstInsurance = base * 0.1;
    return { premium: base + firstInsurance + PROCESSING_FEE };
  });
  return { results };
};

