  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const itemBase = (item: Item): number => BASE_PREMIUM[item.type];

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + itemBase(item), 0);
    const firstInsurance = base * 0.1;
    return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
  });
  return { results };
};

